import React from 'react';

function DisplayStockData({ stockData }) {
  if (!stockData) {
    return <p>Enter a symbol to fetch data</p>;
  }
  return (
    <div className='info'>
      <p>{stockData.symbol}</p>
      <p>{stockData.price}</p>
      <p>{stockData.change}</p>
      <p>{stockData.pChange}</p>
    </div>
  );
}

export default DisplayStockData;
